const investors = $input.all().map(i => i.json);
const tracking  = $('Aggregate Tracking').first().json.tracking || [];
return [{ json: { investors, tracking } }];

const { tracking, investors } = $json;
const byId = {};
for (const inv of (investors || [])) byId[(inv.investor_id || '').toUpperCase()] = inv;

function parseTsList(v) {
  if (!v || v === 'N/A') return [];
  return String(v).replace(/^\[/,'').replace(/\]$/,'').split(',').map(s=>s.trim()).filter(s=>s&&s!=='N/A');
}
function gmailSecs(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  return isNaN(d.getTime()) ? '' : String(Math.floor(d.getTime()/1000));
}

const rows = [];
for (const row of (tracking || [])) {
  const count      = Number(row['followup count'] || 0);
  const timestamps = parseTsList(row['followup timestamps']);
  if (count <= 0 && !timestamps.length) continue;
  if (String(row['not_interested_outreach']||'false').toLowerCase() === 'true') continue;
  const inv  = byId[(row.inv_id||'').toUpperCase()] || {};
  const email= inv.Email || inv.email || '';
  if (!email || !timestamps[0]) continue;
  const ourReplies  = parseTsList(row['our_reply_sent_at']);
  const latestOurs  = ourReplies.length ? ourReplies[ourReplies.length - 1] : null;
  const searchAfter = latestOurs || timestamps[0];
  rows.push({
    inv_id: row.inv_id, email, company: inv.Company||'',
    first_followup_at: timestamps[0], first_followup_timestamp: timestamps[0],
    gmail_after_seconds: gmailSecs(searchAfter), 'followup count': String(count)
  });
}
return [{ json: { contacted: rows, count: rows.length } }];

const tracking = $json.tracking || [];
const DAY_MS   = 24 * 60 * 60 * 1000;
const now      = new Date();

function parseTimestampList(value) {
  if (!value || value === 'N/A') return [];
  const s = typeof value === 'string' ? value : JSON.stringify(value);
  return s.replace(/^\[/, '').replace(/\]$/, '').split(',').map(e => e.trim()).filter(Boolean);
}

function nextFollowup(row) {
  const count      = Number(row['followup count'] || 0);
  const timestamps = parseTimestampList(row['followup timestamps']);

  if (count <= 0) return { due: true, number: 0, reason: 'first contact not sent yet' };

  if (count === 1 && timestamps[0]) {
    return { due: now - new Date(timestamps[0]) >= 2 * DAY_MS, number: 1, reason: '1st follow-up due 2 days after initial' };
  }
  if (count === 2 && timestamps[1]) {
    return { due: now - new Date(timestamps[1]) >= 3 * DAY_MS, number: 2, reason: '2nd follow-up due 3 days after 1st' };
  }
  if (count === 3 && timestamps[2]) {
    return { due: now - new Date(timestamps[2]) >= 5 * DAY_MS, number: 3, reason: '3rd follow-up due 5 days after 2nd' };
  }
  return { due: false, number: null, reason: 'all follow-ups complete or not due' };
}

const eligible = tracking
  .map(row => {
    const replied  = row.reply_timestamp && row.reply_timestamp !== 'N/A';
    const followup = nextFollowup(row);
    return { ...row, evaluation_now: now.toISOString(), followup_count: Number(row['followup count'] || 0), next_followup_number: followup.number, due_reason: followup.reason, is_due: followup.due && !replied };
  })
  .filter(row => row.is_due);

return eligible.map(row => ({ json: row }));

const inv = $json;
const email = inv.Email || inv.email || inv.mail || '';
const investor_id = inv.investor_id || '';
const tr = $('Loop Over Investors').item.json;
return [{ json: {
  investor_email: email,
  investor: { ...inv, investor_id },
  current_followup_count:      Number(tr['followup count'] || 0),
  current_followup_timestamps: tr['followup timestamps'] || '[N/A, N/A, N/A]',
  current_real_first_sent_at:  tr.real_first_sent_at || ''
} }];

const text = $json.text ?? $json.content?.parts?.[0]?.text ?? $json.content ?? '';
const str = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
const parsed = JSON.parse(str);
if (!parsed.subject || !parsed.body) {
  throw new Error('Missing subject or body. Keys: ' + JSON.stringify(Object.keys(parsed)));
}

const parts = parsed.body.split(/\n---\n/);
const body      = parts[0].trim();
const signature = parts.length > 1 ? parts[1].trim() : '';

return [{ json: { subject: parsed.subject, body, signature } }];

const merged = $('Merge').item.json;
const count    = Number(merged.current_followup_count || 0);
const newCount = count + 1;
const now      = $now.toISO();

const tsStr = merged.current_followup_timestamps || '[N/A, N/A, N/A, N/A]';
const slots = tsStr.replace(/^\[/, '').replace(/\]$/, '').split(',').map(s => s.trim());
while (slots.length < 4) slots.push('N/A');
for (let i = 0; i < slots.length; i++) {
  if (!slots[i] || slots[i] === 'N/A') { slots[i] = now; break; }
}

const invId     = merged.investor?.investor_id || merged.investor_id || '';

return [{ json: {
  inv_id:                invId,
  'followup count':      newCount,
  'followup timestamps': `[${slots.join(', ')}]`,
  reply_timestamp:       'N/A',
  'admin notfication':   'false',
} }];

const contacted = $input.first().json.contacted || [];

const rows = contacted
  .filter((row) => row.email && row.first_followup_at && row.gmail_after_seconds)
  .map((row) => ({
    ...row,
    gmail_query: `from:${row.email} in:inbox after:${row.gmail_after_seconds}`,
    admin_email: 'ajinkya.bhandare.work@gmail.com',
  }));

if (rows.length === 0) {
  return [{ json: { _no_op: true, email: '', inv_id: '', 'followup count': '0' } }];
}

return rows.map((row) => ({ json: row }));

const row = $('Merge Reply Data').first().json;
return [{ json: {
  inv_id:              row.inv_id,
  'admin notfication': 'true',
  reply_timestamp:     $now.toISO()
} }];

const sent = $input.all().filter(i => i.json.internalDate);

let dateStr;
if (sent.length > 0) {
  const oldest = sent.reduce((min, i) =>
    parseInt(i.json.internalDate) < parseInt(min.json.internalDate) ? i : min
  , sent[0]);
  const d = new Date(parseInt(oldest.json.internalDate));
  dateStr = `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
} else {
  const fallback = $('Loop Over Investors1').item.json.gmail_after_seconds;
  const d = new Date(parseInt(fallback, 10) * 1000);
  dateStr = `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
}

return [{ json: { reply_query_date: dateStr, found_in_gmail: sent.length > 0 } }];

const replyData = $('Merge Reply Data').first().json;
return [{ json: {
  inv_id:    replyData.inv_id || '',
  direction: 'investor_reply',
  timestamp: $now.toISO(),
  summary: $input.first().json.summary
}}];

const gemmaOut = $input.first().json;
const original = $('Prepare Reply Log Entry').first().json;

let aiSummary = '';
let aiType = '';

// Gemma thinking model returns content.parts[] - find the non-thought part
const parts = gemmaOut?.content?.parts;
if (Array.isArray(parts)) {
  const responsePart = parts.find(p => !p.thought && typeof p.text === 'string');
  if (responsePart) {
    try {
      const parsed = JSON.parse(responsePart.text.trim());
      aiSummary = String(parsed.summary || '');
      aiType    = String(parsed.type    || '');
    } catch (e) {
      aiSummary = responsePart.text.trim();
    }
  }
}

// Fallback: flat response shapes
if (!aiSummary) {
  const raw = gemmaOut.summary || gemmaOut.text || gemmaOut.output || '';
  if (raw && typeof raw === 'string') {
    try {
      const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
      const parsed  = JSON.parse(cleaned);
      aiSummary = String(parsed.summary || '');
      aiType    = String(parsed.type    || '');
    } catch (e) {
      aiSummary = raw.trim();
    }
  }
}

const validTypes = [
  'investor_interested',
  'meeting_requested',
  'investor_question',
  'conditional_interest',
  'investor_rejection',
  'out_of_office',
  'referral',
  'unsubscribe'
];
const direction = validTypes.includes(aiType) ? aiType : 'investor_interested';

if (!aiSummary) {
  aiSummary = typeof original.summary === 'string' ? original.summary : '';
}

return [{ json: {
  inv_id:    String(original.inv_id    || ''),
  direction: direction,
  timestamp: String(original.timestamp || $now.toISO()),
  summary:   aiSummary.trim()
}}];

const rows = $input.all();
const invId = $('Merge').first().json.investor?.investor_id || '';

const row = rows.find(r => (r.json.inv_id || '').toUpperCase() === invId.toUpperCase());

let resolvedConversationId = '';
let hasThread = false;

if (row && row.json.thread_ids) {
  const ids = String(row.json.thread_ids)
    .replace(/^\[/, '').replace(/\]$/, '')
    .split(',').map(s => s.trim()).filter(Boolean);

  const lastEntry = ids[ids.length - 1] || '';

  if (lastEntry) {
    resolvedConversationId = lastEntry;
    hasThread = true;
  }
}

return [{ json: {
  ...($('Merge').first().json),
  resolved_conversation_id: resolvedConversationId,
  has_existing_thread: hasThread
}}];

const gmailResponse = $input.first().json;
const thId = gmailResponse.conversationId || '';

const mergeData = $('Merge').first().json;
const invId = mergeData.investor?.investor_id || '';
const email = mergeData.investor_email || '';

const existing = $('Resolve Thread ID').first().json;
let rawIds = existing.resolved_conversation_id
  ? String(existing.resolved_conversation_id).replace(/^\[/, '').replace(/\]$/, '').split(',').map(s => s.trim()).filter(Boolean)
  : [];

if (thId) {
  rawIds = rawIds.filter(item => item !== thId);
  rawIds.push(thId);
}

return [{ json: {
  inv_id:       invId,
  email:        email,
  thread_ids:   '[' + rawIds.join(', ') + ']',
  last_sent_at: $now.toISO()
}}];

const invId = ($('Merge Reply Data').item.json.inv_id || '').toUpperCase();
const conv_log = $input.all()
  .map(i => i.json)
  .filter(e => (e.inv_id || '').toUpperCase() === invId);
return [{ json: { conv_log } }];

const original   = $('Prepare Reply Log Entry').first().json;
const invId      = (original.inv_id || '').toUpperCase();
const convLog    = $('Agg Conv Log').first().json.conv_log || [];
const threadRows = $input.all().map(i => i.json);
const history = convLog
  .filter(e => (e.inv_id || '').toUpperCase() === invId)
  .sort((a, b) => (a.timestamp || '').localeCompare(b.timestamp || ''));
const threadEntry = threadRows.find(r => (r.inv_id || '').toUpperCase() === invId) || {};
const lastEntry   = history.length > 0 ? history[history.length - 1] : {};
return [{ json: {
  inv_id:               original.inv_id,
  email:                threadEntry.email || '',
  snippet:              lastEntry.summary || original.summary || '',
  direction:            lastEntry.direction || original.direction || '',
  conversation_history: history,
  thread_ids:           threadEntry.thread_ids || '',
}}];

const files = $input.all();
const md = files.find(f => f.json.name && f.json.name.endsWith('.md'));
if (!md) throw new Error('No .md file found in Drive folder');
return [{ json: { fileId: md.json.id, fileName: md.json.name } }];

const ctx = $('Build Reply Context').first().json;
const rawIds = (ctx.thread_ids || '').replace(/^\[/, '').replace(/\]$/, '').split(',').map(s => s.trim()).filter(Boolean);
const latestThreadId = rawIds[rawIds.length - 1] || '';
return [{ json: {
  investor_email:  ctx.email || '',
  inv_id:          ctx.inv_id || '',
  thread_id:       latestThreadId
} }];

const gmailOut = $input.first().json;
const invId = $('Merge Reply Data').item.json.inv_id || '';
const sentAt = $now.toISO();
return [{ json: { inv_id: invId, our_reply_sent_at: sentAt, sent_message_id: gmailOut.id || '' } }];

const input = $input.first().json;
const invId = input.inv_id || '';
const newTimestamp = input.our_reply_sent_at || '';

// Existing value is like [val1,val2,] â€” strip brackets then split
const raw = ($('Merge Reply Data').item.json.our_reply_sent_at || '').toString().trim();
const inner = raw.replace(/^\[/, '').replace(/\]$/, '');
const timestamps = inner.split(',').map(t => t.trim()).filter(Boolean);

if (newTimestamp && !timestamps.includes(newTimestamp)) {
  timestamps.push(newTimestamp);
}

// Build as [val1,val2,] with trailing comma
const result = '[' + timestamps.join(',') + ',]';

return [{ json: { inv_id: invId, our_reply_sent_at: result } }];

const tracking = $json.tracking || [];
const DAY_MS = 24 * 60 * 60 * 1000;
const now = new Date();

function parseTsList(v) {
  if (!v || v === 'N/A') return [];
  return String(v).replace(/^\[/, '').replace(/\]$/, '').split(',').map(s => s.trim()).filter(s => s && s !== 'N/A');
}

const eligible = tracking.filter(row => {
  const ourReplies = parseTsList(row['our_reply_sent_at']);
  if (!ourReplies.length) return false;

  const postCount = Number(row['post_reply_followup_count'] || 0);
  if (postCount >= 1) return false;

  if (String(row['not_interested_outreach'] || 'false').toLowerCase() === 'true') return false;

  const latestOurReply = new Date(ourReplies[ourReplies.length - 1]);
  if (isNaN(latestOurReply.getTime())) return false;
  return (now - latestOurReply) >= 2 * DAY_MS;
});

return eligible.map(row => ({ json: row }));

const inv = $json;
const tr = $('Loop Reply FU').item.json;
const email = inv.Email || inv.email || inv.mail || '';
return [{ json: {
  inv_id: tr.inv_id,
  investor_email: email,
  investor_name: inv.Name || inv.name || '',
  company: inv.Company || inv.company || '',
  our_reply_sent_at: tr['our_reply_sent_at'] || '',
  post_reply_followup_count: Number(tr['post_reply_followup_count'] || 0),
  conversation_summary: tr['conversation_summary'] || ''
} }];

const files = $input.all().map(i => i.json);
const md = files.find(f => (f.name || '').endsWith('.md') || (f.mimeType || '').includes('text'));
return [{ json: { file_id: md ? (md.id || md.fileId || '') : '' } }];

const text = $json.text ?? $json.content?.parts?.[0]?.text ?? $json.content ?? '';
const str = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
const parsed = JSON.parse(str);
if (!parsed.subject || !parsed.body) {
  throw new Error('Missing subject or body. Keys: ' + JSON.stringify(Object.keys(parsed)));
}

const parts = parsed.body.split(/\n---\n/);
const body      = parts[0].trim();
const signature = parts.length > 1 ? parts[1].trim() : '';
return [{ json: { subject: parsed.subject, body, signature, skip: parsed.skip === true } }];

const inv = $('Extract Email Reply FU').first().json;
const now = $now.toISO();
const count = Number(inv.post_reply_followup_count || 0) + 1;
return [{ json: {
  inv_id: inv.inv_id,
  post_reply_followup_count: count,
  post_reply_followup_sent_at: now,
  not_interested_reply: 'true'
} }];

const configRow = $('Read Weekly Config').first().json;
let weeklySentCount = Number(configRow.weekly_sent_count) || 0;
const weekStartDateStr = configRow.week_start_date || null;

const now = new Date();
const dayOfWeek = now.getUTCDay();
const daysSinceMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const currentMonday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - daysSinceMonday));

const storedWeekStart = weekStartDateStr ? new Date(weekStartDateStr) : null;
const isNewWeek = !storedWeekStart || currentMonday > storedWeekStart;
if (isNewWeek) weeklySentCount = 0;

const canSend = weeklySentCount < 30;
const weeklyData = { weeklySentCount, weekStartDate: currentMonday.toISOString(), storedWeekStartDate: weekStartDateStr, isNewWeek, canSend };

return $('Fresh Outreach Branch').all().map(item => ({ json: { ...item.json, ...weeklyData } }));

const drop = new Set(['weeklySentCount', 'weekStartDate', 'isNewWeek', 'canSend', 'storedWeekStartDate']);
return $('Check Weekly Limit').all().map(item => {
  const clean = {};
  for (const [k, v] of Object.entries(item.json)) {
    if (!drop.has(k)) clean[k] = v;
  }
  return { json: clean };
});

const tracking = $('Get Tracking Sheet').all();
const investors = $('Get Contacted Investors').all();

const notInterestedIds = new Set(
  tracking
    .filter(i => String(i.json.not_interested_outreach || '').toLowerCase() === 'true')
    .map(i => String(i.json.inv_id || '').toUpperCase())
);

return investors.filter(i => !notInterestedIds.has(String(i.json.investor_id || i.json.inv_id || '').toUpperCase()));

const day = new Date().getDay();
if (day >= 1 && day <= 4) {
  return $input.all();
}
return [];

const day = new Date().getDay();
if (day >= 1 && day <= 2) {
  return $input.all();
}
return [];

const files = $input.all().map(item => ({
  name: item.json.name,
  id: item.json.id
}));
return [{ json: { files } }];

const text = $json.text ?? $json.content?.parts?.[0]?.text ?? $json.content ?? '';
const str = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
const parsed = JSON.parse(str);
if (!parsed.subject || !parsed.body) {
  throw new Error('Missing subject or body. Keys: ' + JSON.stringify(Object.keys(parsed)));
}

const parts = parsed.body.split(/\n---\n/);
const body      = parts[0].trim();
const signature = parts.length > 1 ? parts[1].trim() : '';
const skip      = parsed.skip === true;
return [{ json: { subject: parsed.subject, body, signature, skip } }];

const messages = $input.first().json.data || [];
const investorEmail = $('Build Reply Context').first().json.email.toLowerCase();

function getBody(msg) {
  let body = msg.body?.content || msg.bodyPreview || '';

  // Strip HTML tags if HTML
  if (body.includes('<')) {
    body = body
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, '')
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ');
  }

  // Cut off at quoted reply indicators
  body = body
    .replace(/\r/g, '')
    .split('\n')
    .filter(line => !line.trim().startsWith('>'))
    .join('\n');

  // Remove everything from "On [date] ... wrote:" onwards
  body = body.replace(/\nOn .+?wrote:[\s\S]*/s, '');

  // Remove everything after "---------- Forwarded" or similar
  body = body.replace(/\n[-]{2,}[\s\S]*/s, '');

  // Clean up
  body = body.replace(/\n{3,}/g, '\n\n').trim();

  return body;
}

const sorted = [...messages].sort((a, b) =>
  new Date(a.receivedDateTime) - new Date(b.receivedDateTime)
);

const conversation = sorted.map(msg => {
  const from = msg.from?.emailAddress?.address || '';
  return {
    from,
    subject: msg.subject || '',
    body: getBody(msg),
    direction: from.toLowerCase().includes(investorEmail) ? 'investor' : 'us'
  };
});

return [{ json: { conversation } }];

const invId = $('Build Reply Context').first().json.inv_id.toUpperCase();
const tracking = $('Aggregate Tracking').first().json.tracking || [];
const row = tracking.find(r => (r.inv_id || '').toUpperCase() === invId) || {};

const raw = (row['followup timestamps'] || '').replace(/^\[/, '').replace(/\]$/, '');
const first = raw.split(',').map(s => s.trim()).filter(s => s && s !== 'N/A')[0] || '';

const afterSeconds = first ? Math.floor(new Date(first).getTime() / 1000) - 2 : 0;

return [{ json: { first_outreach_ts: first, after_seconds: afterSeconds } }];

const parts = $json.content?.parts || [];
const text = parts.length > 0
  ? parts.map(p => p.text || '').join('')
  : ($json.text ?? $json.content ?? '');
const str = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
const parsed = JSON.parse(str);
const escalate = parsed.escalate === true;
const escalate_reason = parsed.escalate_reason || '';
const inv_id = $('Build Reply Context').first().json.inv_id || '';
const email = $('Build Reply Context').first().json.email || '';
const company = $('Merge Reply Data').first().json.company || '';
const investor_reply = $('Build Reply Context').first().json.snippet || '';
return [{ json: { inv_id, email, company, escalate, escalate_reason, investor_reply } }];

