const parts = $json.content?.parts || [];
const text = parts.length > 0
  ? parts.map(p => p.text || '').join('')
  : ($json.text ?? $json.content ?? '');
const str = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
const parsed = JSON.parse(str);
const document_ids = parsed.document_ids || [];
const has_docs = document_ids.length > 0;
return [{ json: { document_ids, has_docs } }];

const items = $input.all();
const result = { json: { count: items.length }, binary: {} };
for (let i = 0; i < items.length; i++) {
  if (items[i].binary && items[i].binary.data) {
    result.binary["data_" + i] = items[i].binary.data;
  }
}
return [result];

const tracking = $json.tracking || [];
const active = tracking.filter(row => (row.timezone || '').toLowerCase() === 'active');
return [{ json: { tracking: active } }];

const body = $input.first().json.body || {};

// Raw HTML
let rawHtml = body.content || $input.first().json.bodyPreview || '';

// ------------------------------
// 1. Keep only latest reply
// ------------------------------
rawHtml = rawHtml
  .split(/<div[^>]*class="gmail_quote/i)[0]
  .split(/<blockquote/i)[0]
  .split(/<hr/i)[0];

// ------------------------------
// 2. Extract investor email
// ------------------------------
let investorEmail = '';

const emailRegex = /mailto:([^"]+)/gi;
const matches = [...rawHtml.matchAll(emailRegex)];

if (matches.length > 0) {
  investorEmail = matches[0][1].trim().toLowerCase();
}

// ------------------------------
// 3. Convert HTML to text
// ------------------------------
function convertHtmlToText(html) {
  return String(html)
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const plainTextBody = convertHtmlToText(rawHtml);

// ------------------------------
// 4. Return
// ------------------------------
