const currentUtcHour = new Date().getUTCHours();
const currentUtcMinute = new Date().getUTCMinutes();
const utcDecimal = currentUtcHour + currentUtcMinute / 60;
const minOffset = 9 - utcDecimal;
const maxOffset = 23 - utcDecimal;
const query = 'SELECT A WHERE AF >= ' + minOffset + ' AND AF < ' + maxOffset;
return [{ json: { minOffset, maxOffset, query, utcHour: currentUtcHour, label: '9AM-11AM local window' } }];

const raw = $input.first().json.data || $input.first().json.body || '';
const jsonStr = raw.substring(raw.indexOf('{'), raw.lastIndexOf('}') + 1);
const parsed = JSON.parse(jsonStr);

const rows = parsed.table?.rows || [];
const invIds = rows.map(r => r.c?.[0]?.v).filter(Boolean);
const count = invIds.length;
const calcData = $('TZ Calculate Active Offset Window (9AM-11AM)').first().json;

return [{ json: {
  found: count > 0,
  invIds,
  count,
  minOffset: calcData.minOffset,
  maxOffset: calcData.maxOffset,
  utcHour: calcData.utcHour,
  debug: count > 0
    ? '9AM-11AM window: found ' + count + ' investors (' + invIds.join(', ') + ') | offsets ' + calcData.minOffset.toFixed(2) + ' to ' + calcData.maxOffset.toFixed(2)
    : '9AM-11AM window: no investors found (offsets ' + calcData.minOffset.toFixed(2) + ' to ' + calcData.maxOffset.toFixed(2) + ', utcHour=' + calcData.utcHour + ')'
} }];

const rows = $input.all().filter(i => i.json.inv_id);
const lastRow = rows.length + 1; // +1 for header row
return [{ json: { lastRow } }];

const invIds = $input.first().json.invIds || [];
